22	// ─── Helpers ────────────────────────────────────────────────────────────────
23	
24	interface BufferedClient {
25	  ws: WebSocket;
26	  messages: Uint8Array[];
27	  waitForMessage: (timeoutMs?: number) => Promise<Uint8Array>;
