30	/** Open a WebSocket with a buffered message queue. */
31	function connectClient(url: string): Promise<BufferedClient> {
32	  return new Promise((resolve, reject) => {
33	    const ws = new WebSocket(url);
34	    ws.binaryType = "arraybuffer";
35	    const messages: Uint8Array[] = [];
36	    const waiters: Array<{
37	      resolve: (msg: Uint8Array) => void;
38	      reject: (err: Error) => void;
39	      timer: ReturnType<typeof setTimeout>;
40	    }> = [];
41	
42	    ws.on("message", (data: ArrayBuffer | Buffer) => {
43	      let msg: Uint8Array;
44	      if (data instanceof ArrayBuffer) {
45	        msg = new Uint8Array(data);
46	      } else {
47	        const buf = data as Buffer;
48	        msg = new Uint8Array(buf.buffer, buf.byteOffset, buf.byteLength);
49	      }
50	      if (waiters.length > 0) {
51	        const waiter = waiters.shift()!;
52	        clearTimeout(waiter.timer);
53	        waiter.resolve(msg);
54	      } else {
55	        messages.push(msg);
56	      }
57	    });
58	
59	    const waitForMessage = (timeoutMs = 3000): Promise<Uint8Array> => {
60	      if (messages.length > 0) {
61	        return Promise.resolve(messages.shift()!);
62	      }
63	      return new Promise((res, rej) => {
64	        const entry: typeof waiters[0] = {
65	          resolve: res,
66	          reject: rej,
67	          timer: setTimeout(() => {
68	            // Remove this waiter from the queue so it doesn't consume future messages
69	            const idx = waiters.indexOf(entry);
70	            if (idx !== -1) waiters.splice(idx, 1);
71	            rej(new Error("waitForMessage timed out"));
72	          }, timeoutMs),
73	        };
74	        waiters.push(entry);
75	      });
76	    };
77	
78	    ws.on("open", () => resolve({ ws, messages, waitForMessage }));
79	    ws.on("error", reject);
80	  });
81	}
