92	/**
93	 * Perform a full Yjs sync handshake with a buffered client.
94	 * Returns a Y.Doc populated with the server document state.
95	 */
96	async function performSync(client: BufferedClient): Promise<Y.Doc> {
97	  const doc = new Y.Doc();
98	
99	  // 1. Receive server's sync step 1
100	  const msg1 = await client.waitForMessage();
101	  const decoder1 = decoding.createDecoder(msg1);
102	  const type1 = decoding.readVarUint(decoder1);
103	  expect(type1).toBe(MSG_SYNC);
104	
105	  // Generate and send our sync step 2 (response to server's step 1)
106	  const respEncoder = encoding.createEncoder();
107	  encoding.writeVarUint(respEncoder, MSG_SYNC);
108	  syncProtocol.readSyncMessage(decoder1, respEncoder, doc, null);
109	  if (encoding.length(respEncoder) > 1) {
110	    client.ws.send(encoding.toUint8Array(respEncoder));
111	  }
112	
113	  // 2. Send our own sync step 1 to request the server's data
114	  const step1Encoder = encoding.createEncoder();
115	  encoding.writeVarUint(step1Encoder, MSG_SYNC);
116	  syncProtocol.writeSyncStep1(step1Encoder, doc);
117	  client.ws.send(encoding.toUint8Array(step1Encoder));
118	
119	  // 3. Process a few response messages (sync step 2, awareness, etc.)
120	  //    Use a short timeout for draining — the handshake should complete quickly.
121	  for (let i = 0; i < 5; i++) {
122	    try {
123	      const msg = await client.waitForMessage(500);
124	      const decoder = decoding.createDecoder(msg);
125	      const msgType = decoding.readVarUint(decoder);
126	      if (msgType === MSG_SYNC) {
127	        const encoder = encoding.createEncoder();
128	        syncProtocol.readSyncMessage(decoder, encoder, doc, null);
129	      }
130	    } catch {
131	      // Timeout is fine — just means no more handshake messages
132	      break;
133	    }
134	  }
135	
136	  return doc;
137	}
